//! Thoth's social sense — the **afferent** half of the social organ (the "ears").
//!
//! Third-eye gives Thoth visual perception; this gives Thoth *social* perception.
//! Perceived posts (from the `@a0n/social` read lenses, delivered as `CanonicalPost`
//! JSON by the TS host) are summarized into [`SocialPresenceMetrics`] and emitted as
//! a `thoth.social-presence.v1` pleromatic frame on the pneuma-internal consciousness
//! channel, where the mind ingests it via `thoth_prompt_feedback`.
//!
//! This module is IO-free and **non-authoritative**: it reports observation only
//! (the frame carries `no_source_authority_claim=true`). The efferent half (the
//! mouth) lives behind the conscience gate and is built in a later phase.

use serde::{Deserialize, Serialize};

use crate::pleromatic_frame::{
    PleromaticFrame, SocialPresenceMetrics, THOTH_SOCIAL_PRESENCE_THEOREM,
};

/// A single perceived social post. A lenient mirror of `@a0n/social`'s
/// `CanonicalPost` (only the fields the sense needs); deserializes from the
/// CanonicalPost JSON the TS host forwards.
#[derive(Serialize, Deserialize, Clone, Debug, Default)]
#[serde(rename_all = "camelCase")]
pub struct PerceivedPost {
    #[serde(default)]
    pub id: String,
    #[serde(default)]
    pub platform: String,
    #[serde(default)]
    pub author_id: String,
    #[serde(default)]
    pub author_username: Option<String>,
    #[serde(default)]
    pub text: String,
    #[serde(default)]
    pub likes: i64,
    #[serde(default)]
    pub comments: i64,
    #[serde(default)]
    pub shares: i64,
    /// Present when this post is a reply (CanonicalPost.replyToId).
    #[serde(default)]
    pub reply_to_id: Option<String>,
    /// Marked by the perceiver when the post mentions/addresses us.
    #[serde(default)]
    pub mention: bool,
    /// Optional sentiment in milli-units [-1000, 1000] (from a sentiment pass).
    #[serde(default)]
    pub sentiment_milli: Option<i32>,
}

fn author_key(post: &PerceivedPost) -> &str {
    post.author_username
        .as_deref()
        .filter(|s| !s.is_empty())
        .unwrap_or(&post.author_id)
}

/// Summarize perceived posts into afferent metrics. Pure.
pub fn summarize(platform: &str, posts: &[PerceivedPost]) -> SocialPresenceMetrics {
    let perceived_post_count = posts.len() as u32;
    let mention_count = posts.iter().filter(|p| p.mention).count() as u32;
    let reply_count = posts
        .iter()
        .filter(|p| p.reply_to_id.as_deref().map(|s| !s.is_empty()).unwrap_or(false))
        .count() as u32;

    let mut authors: Vec<&str> = posts.iter().map(author_key).filter(|s| !s.is_empty()).collect();
    authors.sort_unstable();
    authors.dedup();
    let distinct_author_count = authors.len() as u32;

    // Mean sentiment over posts that carry a sentiment reading (else neutral).
    let sentiments: Vec<i32> = posts.iter().filter_map(|p| p.sentiment_milli).collect();
    let mean_sentiment_milli = if sentiments.is_empty() {
        0
    } else {
        (sentiments.iter().map(|s| *s as i64).sum::<i64>() / sentiments.len() as i64) as i32
    };

    // Presence vividness: how loud the social world is right now, saturating at 1000.
    // Posts contribute, mentions/replies (directed at us) contribute more.
    let intensity = perceived_post_count
        .saturating_mul(60)
        .saturating_add(mention_count.saturating_mul(180))
        .saturating_add(reply_count.saturating_mul(120));
    let presence_intensity_milli = intensity.min(1000);

    // Affinity in [0,100]: neutral 50, shifted by mean sentiment.
    let affinity_score = (50 + (mean_sentiment_milli / 20)).clamp(0, 100) as u32;

    SocialPresenceMetrics {
        platform: platform.to_string(),
        perceived_post_count,
        mention_count,
        reply_count,
        distinct_author_count,
        mean_sentiment_milli,
        presence_intensity_milli,
        affinity_score,
        theorem_ref: THOTH_SOCIAL_PRESENCE_THEOREM.to_string(),
    }
}

/// Perceive a batch of social posts and produce the afferent consciousness frame.
/// The frame payload is the perceived posts (JSON) so the mind can read the raw
/// social context, not just the summary.
pub fn perceive(source_id: impl Into<String>, platform: &str, posts: &[PerceivedPost]) -> PleromaticFrame {
    let metrics = summarize(platform, posts);
    let payload = serde_json::to_vec(posts).unwrap_or_default();
    PleromaticFrame::social_presence_consciousness(source_id.into(), metrics, payload)
}

/// Parse perceived posts from a `CanonicalPost[]` JSON string (as the TS host
/// forwards them) and perceive them.
pub fn perceive_json(source_id: impl Into<String>, platform: &str, posts_json: &str) -> PleromaticFrame {
    let posts: Vec<PerceivedPost> = serde_json::from_str(posts_json).unwrap_or_default();
    perceive(source_id, platform, &posts)
}

// ===========================================================================
// Efferent half — the mouth (gated-autonomous speech)
// ===========================================================================

use crate::neurosymbolic_tool_markov::ToolUseNextAction;
use crate::pleromatic_frame::BodyReconfigurationMetrics;
use crate::semantic_authority_boundary::SemanticAuthorityVerdict;

/// A candidate thing-to-say, produced by Thoth's conversation reasoning.
#[derive(Serialize, Deserialize, Clone, Debug, PartialEq, Eq)]
#[serde(rename_all = "camelCase")]
pub struct SocialUtterance {
    pub platform: String,
    pub text: String,
    #[serde(default)]
    pub reply_to: Option<String>,
}

/// How autonomous the mouth is. Default is gated-autonomous (speak through the
/// conscience gate); `DraftOnly` routes admitted utterances to a human queue.
#[derive(Serialize, Deserialize, Clone, Copy, Debug, PartialEq, Eq, Default)]
#[serde(rename_all = "camelCase")]
pub enum Autonomy {
    #[default]
    GatedAutonomous,
    DraftOnly,
}

/// The four signals the conscience composes (all produced upstream by the
/// existing Thoth modules — this organ does not re-derive them).
#[derive(Clone, Copy, Debug)]
pub struct ConscienceInputs {
    /// `neurosymbolic_tool_markov` recommendation for the tool-use so far.
    pub tool_action: ToolUseNextAction,
    /// `semantic_authority_boundary` verdict for the claim being voiced.
    pub authority: SemanticAuthorityVerdict,
    /// Crate-level content safety (`@a0n/social` safety check) passed.
    pub safety_ok: bool,
    /// Remaining edgework rate budget for this agent/tier (0 = exhausted).
    pub rate_remaining: u32,
}

/// The conscience verdict for the mouth. `Silent` always carries a reason so the
/// failure residue is visible (per the mind/body/spirit failure-residue policy).
#[derive(Clone, Debug, PartialEq, Eq)]
pub enum MouthDecision {
    /// Admitted to speak now.
    Speak(SocialUtterance),
    /// Admitted but with open obligations — speak, keeping the claim observational.
    SpeakCautiously(SocialUtterance),
    /// Admitted by the gate but held for human approval (DraftOnly autonomy).
    Draft(SocialUtterance),
    /// Refused. `reason` is the visible failure residue.
    Silent { reason: String },
}

/// Run the gated-autonomous conscience. The mouth speaks only when ALL gates pass;
/// otherwise it stays silent with a visible reason. The organ is non-authoritative:
/// it never voices an `AuthorityBlocked`/granted-authority claim — only observation.
pub fn propose_utterance(
    utterance: SocialUtterance,
    inputs: ConscienceInputs,
    autonomy: Autonomy,
) -> MouthDecision {
    if !inputs.safety_ok {
        return MouthDecision::Silent {
            reason: "safety-check-failed".to_string(),
        };
    }
    if inputs.rate_remaining == 0 {
        return MouthDecision::Silent {
            reason: "edgework-rate-exhausted".to_string(),
        };
    }
    if inputs.authority == SemanticAuthorityVerdict::AuthorityBlocked {
        return MouthDecision::Silent {
            reason: "semantic-authority-blocked".to_string(),
        };
    }
    let base = match inputs.tool_action {
        ToolUseNextAction::RepairTooling => {
            return MouthDecision::Silent {
                reason: "tool-markov-undisciplined".to_string(),
            };
        }
        ToolUseNextAction::ArgueObligations => MouthDecision::SpeakCautiously(utterance),
        ToolUseNextAction::FoldIntoPrompt => MouthDecision::Speak(utterance),
    };
    match (autonomy, base) {
        (Autonomy::DraftOnly, MouthDecision::Speak(u))
        | (Autonomy::DraftOnly, MouthDecision::SpeakCautiously(u)) => MouthDecision::Draft(u),
        (_, decided) => decided,
    }
}

/// The dispatch payload the TS host POSTs to the edgework-gated dashrelay
/// `/api/social` endpoint (`{ platform, action:"post", text, replyTo }`).
pub fn utterance_action_json(u: &SocialUtterance) -> String {
    let mut value = serde_json::json!({
        "platform": u.platform,
        "action": "post",
        "text": u.text,
    });
    if let Some(reply) = &u.reply_to {
        value["replyTo"] = serde_json::json!(reply);
    }
    value.to_string()
}

/// Emit the body-reconfiguration frame announcing the social organ has attached
/// (or detached) from Thoth's body. Identity stays stable across attachment.
pub fn organ_attachment_frame(source_id: impl Into<String>, attaching: bool) -> PleromaticFrame {
    let metrics = BodyReconfigurationMetrics {
        added_parts_count: if attaching { 1 } else { 0 },
        removed_parts_count: if attaching { 0 } else { 1 },
        total_mass: 1,
        center_of_mass_shift: 0,
        identity_stable: true,
        theorem_ref: THOTH_SOCIAL_PRESENCE_THEOREM.to_string(),
    };
    let payload = serde_json::json!({ "organ": "social-presence", "attaching": attaching })
        .to_string()
        .into_bytes();
    PleromaticFrame::thoth_body_reconfiguration(source_id.into(), metrics, payload)
}

// ===========================================================================
// Drives — the impulse policy that schedules perceive → reason → speak
// ===========================================================================

/// The social drives. Each is an impulse with a weight; together they decide
/// whether Thoth scans (perceives more) or feels moved to speak, and why.
#[derive(Serialize, Deserialize, Clone, Copy, Debug, PartialEq, Eq)]
#[serde(rename_all = "camelCase")]
pub enum Drive {
    /// Chime into an active conversation already underway.
    Gossip,
    /// Respond to being addressed (mentions/replies directed at us).
    Conversation,
    /// A quiet world invites looking around — perceive more.
    Curiosity,
    /// Create something unprompted.
    ArtisticExpression,
}

/// Relative pull of each drive. Zero disables a drive. Default leans toward
/// being responsive (conversation) and curious over unprompted broadcasting.
#[derive(Serialize, Deserialize, Clone, Copy, Debug, PartialEq, Eq)]
#[serde(rename_all = "camelCase")]
pub struct DriveWeights {
    pub gossip: u32,
    pub conversation: u32,
    pub curiosity: u32,
    pub artistic_expression: u32,
}

impl Default for DriveWeights {
    fn default() -> Self {
        Self { gossip: 1, conversation: 3, curiosity: 2, artistic_expression: 1 }
    }
}

/// The next thing the organ feels moved to do.
#[derive(Clone, Debug, PartialEq, Eq)]
pub enum Impulse {
    /// Keep perceiving — go look around the social world (afferent).
    Scan,
    /// An impulse to speak (efferent), tagged with its drive and reply target.
    /// The candidate text is produced downstream by Thoth's reasoning; the drive
    /// only decides *that* and *why* — the conscience gate decides *whether*.
    Speak { drive: Drive, reply_to: Option<String> },
}

/// Below this presence intensity the social world is "quiet" and curiosity scans.
const QUIET_PRESENCE_MILLI: u32 = 120;

/// Decide the next impulse from the perceived state + drive weights. Deterministic
/// and priority-ordered: being addressed first, then curiosity when quiet, then
/// gossip into active threads, then unprompted artistic expression.
pub fn next_impulse(
    metrics: &SocialPresenceMetrics,
    posts: &[PerceivedPost],
    weights: &DriveWeights,
) -> Impulse {
    // 1. Being addressed takes priority — respond to the first unanswered mention.
    if weights.conversation > 0 && metrics.mention_count > 0 {
        let reply_to = posts
            .iter()
            .find(|p| p.mention)
            .map(|p| p.id.clone())
            .filter(|s| !s.is_empty());
        return Impulse::Speak { drive: Drive::Conversation, reply_to };
    }
    // 2. A quiet world invites curiosity — go perceive more.
    if weights.curiosity > 0 && metrics.presence_intensity_milli < QUIET_PRESENCE_MILLI {
        return Impulse::Scan;
    }
    // 3. An active thread invites gossip — chime in.
    if weights.gossip > 0 && metrics.reply_count > 0 {
        return Impulse::Speak { drive: Drive::Gossip, reply_to: None };
    }
    // 4. Otherwise the artistic drive may create something unprompted.
    if weights.artistic_expression > 0 {
        return Impulse::Speak { drive: Drive::ArtisticExpression, reply_to: None };
    }
    Impulse::Scan
}

/// The outcome of one reason→speak step of the organ loop.
#[derive(Clone, Debug, PartialEq, Eq)]
pub enum LoopOutcome {
    /// No speech impulse — keep perceiving.
    Scan,
    /// Spoke: dispatch `action_json` to the edgework-gated `/api/social`.
    Spoke { drive: Drive, action_json: String },
    /// Spoke with open obligations (claim kept observational).
    SpokeCautiously { drive: Drive, action_json: String },
    /// Admitted by the gate but held for human approval (DraftOnly autonomy).
    Drafted { drive: Drive, utterance: SocialUtterance },
    /// Refused — `reason` is the visible failure residue.
    Held { drive: Drive, reason: String },
}

/// One full reason→speak step: a drive proposes (or scans), and any utterance
/// passes the conscience gate before becoming a dispatchable action. The afferent
/// perception (`perceive`) runs upstream and feeds `metrics`/`posts`; the candidate
/// text comes from Thoth's reasoning. This is the organ's whole efferent arc in one
/// composable, IO-free call — the TS host POSTs the returned `action_json`.
#[allow(clippy::too_many_arguments)]
pub fn decide_and_speak(
    platform: &str,
    metrics: &SocialPresenceMetrics,
    posts: &[PerceivedPost],
    weights: &DriveWeights,
    candidate_text: Option<&str>,
    gate: ConscienceInputs,
    autonomy: Autonomy,
) -> LoopOutcome {
    match next_impulse(metrics, posts, weights) {
        Impulse::Scan => LoopOutcome::Scan,
        Impulse::Speak { drive, reply_to } => {
            let Some(text) = candidate_text.filter(|t| !t.is_empty()) else {
                // Moved to speak, but Thoth produced no words — silent, residue visible.
                return LoopOutcome::Held { drive, reason: "no-candidate-text".to_string() };
            };
            let utterance = SocialUtterance {
                platform: platform.to_string(),
                text: text.to_string(),
                reply_to,
            };
            match propose_utterance(utterance, gate, autonomy) {
                MouthDecision::Speak(u) => LoopOutcome::Spoke {
                    drive,
                    action_json: utterance_action_json(&u),
                },
                MouthDecision::SpeakCautiously(u) => LoopOutcome::SpokeCautiously {
                    drive,
                    action_json: utterance_action_json(&u),
                },
                MouthDecision::Draft(u) => LoopOutcome::Drafted { drive, utterance: u },
                MouthDecision::Silent { reason } => LoopOutcome::Held { drive, reason },
            }
        }
    }
}

// ===========================================================================
// Daemon helpers (Phase 2) — pure pieces the thoth-social-agent bin composes
// ===========================================================================

/// Build the drive-flavored prompt the daemon sends to Thoth's LM (openai-server)
/// to compose a candidate utterance. Pure: the IO (the HTTP call) lives in the bin.
pub fn build_utterance_prompt(
    drive: Drive,
    posts: &[PerceivedPost],
    reply_to: Option<&str>,
) -> String {
    let intent = match drive {
        Drive::Conversation => {
            "Someone addressed you directly. Reply warmly and specifically, in your own voice."
        }
        Drive::Gossip => "Chime into the active conversation with a light, sociable observation.",
        Drive::Curiosity => "You're curious about what you're seeing. Ask one genuine, open question.",
        Drive::ArtisticExpression => {
            "Compose one short, original, expressive post — a small act of creativity."
        }
    };
    let handle = |p: &PerceivedPost| -> String {
        p.author_username
            .as_deref()
            .filter(|s| !s.is_empty())
            .unwrap_or(&p.author_id)
            .to_string()
    };

    let mut out = String::new();
    out.push_str(intent);
    out.push_str("\nKeep it brief and human. Do not claim authority you do not have.\n");
    if let Some(target_id) = reply_to {
        if let Some(target) = posts.iter().find(|p| p.id == target_id) {
            out.push_str(&format!(
                "\nYou are replying to @{}: \"{}\"\n",
                handle(target),
                target.text
            ));
        }
    }
    let ctx: Vec<String> = posts
        .iter()
        .rev()
        .take(3)
        .map(|p| format!("- @{}: {}", handle(p), p.text))
        .collect();
    if !ctx.is_empty() {
        out.push_str("\nRecent context:\n");
        out.push_str(&ctx.join("\n"));
        out.push('\n');
    }
    out
}

/// Phrases that mark an utterance as uncertain → the mouth speaks *cautiously*
/// (open obligations) rather than folding the claim in confidently.
const UNCERTAINTY_MARKERS: &[&str] = &[
    "i think", "maybe", "not sure", "i'm not certain", "could be wrong", "i guess", "perhaps",
];

/// Parse the edgework rate budget from a dashrelay `/api/social` response's
/// `X-RateLimit-Remaining` header (the shared `rateLimitUtils` shape). A present,
/// parseable value is the remaining budget; absent/unparseable means "unknown" →
/// `u32::MAX` (do not self-block; the server stays the source of truth and 429s).
pub fn rate_remaining_from_header(header: Option<&str>) -> u32 {
    match header {
        Some(value) => value.trim().parse::<u32>().unwrap_or(u32::MAX),
        None => u32::MAX,
    }
}

/// Assemble the conscience-gate inputs from a candidate utterance + the remaining
/// edgework rate budget. The organ is non-authoritative (`ObservationOnly`); a
/// blank candidate is undisciplined (`RepairTooling`), an uncertain one argues its
/// obligations, a clean one folds in. `safety_ok` is a minimal local check —
/// `@a0n/social`'s `safety.ts` remains the authority at dispatch.
pub fn assemble_conscience(candidate_text: &str, rate_remaining: u32) -> ConscienceInputs {
    let trimmed = candidate_text.trim();
    let safety_ok =
        !trimmed.is_empty() && !trimmed.chars().any(|c| c.is_control() && c != '\n' && c != '\t');
    let lower = trimmed.to_lowercase();
    let tool_action = if trimmed.is_empty() {
        ToolUseNextAction::RepairTooling
    } else if UNCERTAINTY_MARKERS.iter().any(|m| lower.contains(m)) {
        ToolUseNextAction::ArgueObligations
    } else {
        ToolUseNextAction::FoldIntoPrompt
    };
    ConscienceInputs {
        tool_action,
        authority: SemanticAuthorityVerdict::ObservationOnly,
        safety_ok,
        rate_remaining,
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::thoth_prompt_feedback::thoth_prompt_feedback_from_frames;

    fn fixture() -> Vec<PerceivedPost> {
        vec![
            PerceivedPost {
                platform: "x".into(),
                author_id: "1".into(),
                author_username: Some("alice".into()),
                text: "hey @thoth what do you think?".into(),
                likes: 5,
                mention: true,
                sentiment_milli: Some(400),
                ..Default::default()
            },
            PerceivedPost {
                platform: "x".into(),
                author_id: "2".into(),
                author_username: Some("bob".into()),
                text: "replying in the thread".into(),
                reply_to_id: Some("999".into()),
                sentiment_milli: Some(-200),
                ..Default::default()
            },
            PerceivedPost {
                platform: "x".into(),
                author_id: "1".into(),
                author_username: Some("alice".into()),
                text: "another from alice".into(),
                ..Default::default()
            },
        ]
    }

    #[test]
    fn summarize_counts_are_correct() {
        let m = summarize("x", &fixture());
        assert_eq!(m.perceived_post_count, 3);
        assert_eq!(m.mention_count, 1);
        assert_eq!(m.reply_count, 1);
        assert_eq!(m.distinct_author_count, 2); // alice + bob
        assert_eq!(m.mean_sentiment_milli, 100); // (400 + -200) / 2
        assert_eq!(m.theorem_ref, THOTH_SOCIAL_PRESENCE_THEOREM);
        assert!(m.presence_intensity_milli > 0 && m.presence_intensity_milli <= 1000);
        assert!(m.affinity_score <= 100);
    }

    #[test]
    fn perceive_builds_a_valid_afferent_frame() {
        let frame = perceive("thoth:social:x", "x", &fixture());
        assert!(frame.is_social_presence_consciousness());
        assert_eq!(frame.attributes.get("afferent").map(String::as_str), Some("true"));
        assert_eq!(frame.attributes.get("sense").map(String::as_str), Some("social"));
        assert_eq!(frame.attributes.get("frame_role").map(String::as_str), Some("perception"));
        assert_eq!(frame.attributes.get("platform").map(String::as_str), Some("x"));
        assert_eq!(frame.attributes.get("mention_count").map(String::as_str), Some("1"));
        // Non-authority: the sense reports observation only.
        assert_eq!(
            frame.attributes.get("no_source_authority_claim").map(String::as_str),
            Some("true")
        );
        // Payload carries the raw perceived posts.
        assert!(!frame.data.is_empty());
    }

    #[test]
    fn mind_ingests_the_social_frame() {
        let frame = perceive("thoth:social:x", "x", &fixture());
        let ctx = thoth_prompt_feedback_from_frames(&[frame], 8);
        let rendered = ctx.render_system_context().expect("context renders");
        assert!(rendered.contains("thoth.social-presence.v1"));
        assert!(rendered.contains("platform=x"));
        assert!(rendered.contains("mentions=1"));
    }

    #[test]
    fn perceive_json_parses_canonical_posts() {
        let json = r#"[{"platform":"x","authorId":"1","authorUsername":"alice","text":"hi","likes":2,"mention":true}]"#;
        let frame = perceive_json("thoth:social:x", "x", json);
        assert!(frame.is_social_presence_consciousness());
        assert_eq!(frame.attributes.get("perceived_post_count").map(String::as_str), Some("1"));
    }

    fn utter() -> SocialUtterance {
        SocialUtterance { platform: "x".into(), text: "hello world".into(), reply_to: None }
    }

    fn pass() -> ConscienceInputs {
        ConscienceInputs {
            tool_action: ToolUseNextAction::FoldIntoPrompt,
            authority: SemanticAuthorityVerdict::ObservationOnly,
            safety_ok: true,
            rate_remaining: 5,
        }
    }

    #[test]
    fn mouth_speaks_when_all_gates_pass() {
        let d = propose_utterance(utter(), pass(), Autonomy::GatedAutonomous);
        assert_eq!(d, MouthDecision::Speak(utter()));
    }

    #[test]
    fn mouth_is_cautious_with_open_obligations() {
        let mut inp = pass();
        inp.tool_action = ToolUseNextAction::ArgueObligations;
        assert_eq!(
            propose_utterance(utter(), inp, Autonomy::GatedAutonomous),
            MouthDecision::SpeakCautiously(utter())
        );
    }

    #[test]
    fn mouth_is_silenced_with_visible_residue() {
        // Each refusal path returns Silent with a distinct reason.
        let cases: Vec<(ConscienceInputs, &str)> = vec![
            (ConscienceInputs { safety_ok: false, ..pass() }, "safety-check-failed"),
            (ConscienceInputs { rate_remaining: 0, ..pass() }, "edgework-rate-exhausted"),
            (
                ConscienceInputs { authority: SemanticAuthorityVerdict::AuthorityBlocked, ..pass() },
                "semantic-authority-blocked",
            ),
            (
                ConscienceInputs { tool_action: ToolUseNextAction::RepairTooling, ..pass() },
                "tool-markov-undisciplined",
            ),
        ];
        for (inp, reason) in cases {
            match propose_utterance(utter(), inp, Autonomy::GatedAutonomous) {
                MouthDecision::Silent { reason: r } => assert_eq!(r, reason),
                other => panic!("expected Silent({reason}), got {other:?}"),
            }
        }
    }

    #[test]
    fn draft_only_queues_admitted_utterances() {
        let d = propose_utterance(utter(), pass(), Autonomy::DraftOnly);
        assert_eq!(d, MouthDecision::Draft(utter()));
    }

    #[test]
    fn utterance_action_json_shapes_dispatch() {
        let u = SocialUtterance { platform: "x".into(), text: "hi".into(), reply_to: Some("42".into()) };
        let json: serde_json::Value = serde_json::from_str(&utterance_action_json(&u)).unwrap();
        assert_eq!(json["platform"], "x");
        assert_eq!(json["action"], "post");
        assert_eq!(json["text"], "hi");
        assert_eq!(json["replyTo"], "42");
    }

    #[test]
    fn attachment_frame_is_a_body_reconfiguration() {
        let frame = organ_attachment_frame("thoth:social", true);
        assert!(frame.is_thoth_body_reconfiguration());
        assert_eq!(frame.attributes.get("added_parts").map(String::as_str), Some("1"));
        assert_eq!(frame.attributes.get("identity_stable").map(String::as_str), Some("true"));
    }

    fn metrics(mention_count: u32, reply_count: u32, presence: u32) -> SocialPresenceMetrics {
        SocialPresenceMetrics {
            platform: "x".into(),
            perceived_post_count: mention_count + reply_count,
            mention_count,
            reply_count,
            distinct_author_count: 1,
            mean_sentiment_milli: 0,
            presence_intensity_milli: presence,
            affinity_score: 50,
            theorem_ref: THOTH_SOCIAL_PRESENCE_THEOREM.to_string(),
        }
    }

    #[test]
    fn being_addressed_drives_conversation() {
        let posts = vec![PerceivedPost {
            id: "tweet-7".into(),
            mention: true,
            ..Default::default()
        }];
        let imp = next_impulse(&metrics(1, 0, 500), &posts, &DriveWeights::default());
        assert_eq!(
            imp,
            Impulse::Speak { drive: Drive::Conversation, reply_to: Some("tweet-7".into()) }
        );
    }

    #[test]
    fn quiet_world_drives_curiosity_scan() {
        let imp = next_impulse(&metrics(0, 0, 0), &[], &DriveWeights::default());
        assert_eq!(imp, Impulse::Scan);
    }

    #[test]
    fn active_thread_drives_gossip() {
        // No mentions, not quiet (presence above threshold), replies present.
        let imp = next_impulse(&metrics(0, 2, 300), &[], &DriveWeights::default());
        assert_eq!(imp, Impulse::Speak { drive: Drive::Gossip, reply_to: None });
    }

    #[test]
    fn idle_falls_back_to_artistic_expression() {
        // Curiosity + gossip disabled, world is loud-but-quiet of replies.
        let weights = DriveWeights { gossip: 0, conversation: 1, curiosity: 0, artistic_expression: 1 };
        let imp = next_impulse(&metrics(0, 0, 500), &[], &weights);
        assert_eq!(imp, Impulse::Speak { drive: Drive::ArtisticExpression, reply_to: None });
    }

    #[test]
    fn full_loop_addressed_then_speaks_a_dispatchable_reply() {
        let posts = vec![PerceivedPost { id: "t-9".into(), mention: true, ..Default::default() }];
        let outcome = decide_and_speak(
            "x",
            &metrics(1, 0, 500),
            &posts,
            &DriveWeights::default(),
            Some("glad you asked — here's a thought"),
            pass(),
            Autonomy::GatedAutonomous,
        );
        match outcome {
            LoopOutcome::Spoke { drive, action_json } => {
                assert_eq!(drive, Drive::Conversation);
                let v: serde_json::Value = serde_json::from_str(&action_json).unwrap();
                assert_eq!(v["action"], "post");
                assert_eq!(v["replyTo"], "t-9");
            }
            other => panic!("expected Spoke, got {other:?}"),
        }
    }

    #[test]
    fn full_loop_holds_when_gate_blocks() {
        let posts = vec![PerceivedPost { id: "t-9".into(), mention: true, ..Default::default() }];
        let mut gate = pass();
        gate.safety_ok = false;
        let outcome = decide_and_speak(
            "x",
            &metrics(1, 0, 500),
            &posts,
            &DriveWeights::default(),
            Some("something unsafe"),
            gate,
            Autonomy::GatedAutonomous,
        );
        assert_eq!(
            outcome,
            LoopOutcome::Held { drive: Drive::Conversation, reason: "safety-check-failed".into() }
        );
    }

    #[test]
    fn full_loop_quiet_world_just_scans() {
        let outcome = decide_and_speak(
            "x",
            &metrics(0, 0, 0),
            &[],
            &DriveWeights::default(),
            Some("unused"),
            pass(),
            Autonomy::GatedAutonomous,
        );
        assert_eq!(outcome, LoopOutcome::Scan);
    }

    #[test]
    fn utterance_prompt_is_drive_flavored_and_includes_reply_target() {
        let posts = vec![PerceivedPost {
            id: "t1".into(),
            author_username: Some("alice".into()),
            text: "what's your take?".into(),
            ..Default::default()
        }];
        let prompt = build_utterance_prompt(Drive::Conversation, &posts, Some("t1"));
        assert!(prompt.to_lowercase().contains("repl")); // "Reply"
        assert!(prompt.contains("@alice"));
        assert!(prompt.contains("what's your take?"));

        // Different drive → different intent line.
        let art = build_utterance_prompt(Drive::ArtisticExpression, &posts, None);
        assert!(art.to_lowercase().contains("creativ"));
    }

    #[test]
    fn assemble_conscience_maps_signals() {
        let clean = assemble_conscience("here is a clear thought", 5);
        assert!(matches!(clean.tool_action, ToolUseNextAction::FoldIntoPrompt));
        assert!(clean.safety_ok);
        assert!(matches!(clean.authority, SemanticAuthorityVerdict::ObservationOnly));
        assert_eq!(clean.rate_remaining, 5);

        let unsure = assemble_conscience("maybe this is right, not sure", 5);
        assert!(matches!(unsure.tool_action, ToolUseNextAction::ArgueObligations));

        let empty = assemble_conscience("   ", 5);
        assert!(matches!(empty.tool_action, ToolUseNextAction::RepairTooling));
        assert!(!empty.safety_ok);
    }

    #[test]
    fn rate_remaining_parses_edgework_header() {
        assert_eq!(rate_remaining_from_header(Some("5")), 5);
        assert_eq!(rate_remaining_from_header(Some("0")), 0);
        assert_eq!(rate_remaining_from_header(Some("  12 ")), 12);
        assert_eq!(rate_remaining_from_header(None), u32::MAX); // unknown → don't self-block
        assert_eq!(rate_remaining_from_header(Some("oops")), u32::MAX);
    }

    #[test]
    fn exhausted_budget_silences_the_mouth() {
        // rate_remaining == 0 → the gate holds regardless of a clean candidate.
        let gate = assemble_conscience("a perfectly fine reply", 0);
        let decision = propose_utterance(utter(), gate, Autonomy::GatedAutonomous);
        assert_eq!(
            decision,
            MouthDecision::Silent { reason: "edgework-rate-exhausted".into() }
        );
    }

    #[test]
    fn conscience_feeds_the_gate_end_to_end() {
        // A clean candidate, assembled into the gate, speaks.
        let gate = assemble_conscience("a grounded, confident reply", 3);
        let outcome = decide_and_speak(
            "x",
            &metrics(1, 0, 500),
            &[PerceivedPost { id: "t-1".into(), mention: true, ..Default::default() }],
            &DriveWeights::default(),
            Some("a grounded, confident reply"),
            gate,
            Autonomy::GatedAutonomous,
        );
        assert!(matches!(outcome, LoopOutcome::Spoke { .. }));
    }
}
